const List<Site> iraqSites = [

  Site(id:'s001', name:'المتحف العراقي', nameEn:'Iraq Museum',
    city:'بغداد', governorate:'بغداد', cityEn:'Baghdad', governorateEn:'Baghdad',
    description:'يُعدّ المتحف العراقي من أعظم متاحف العالم وأكثرها ثراءً بالتاريخ الإنساني، إذ يضم بين جنباته أكثر من 170,000 قطعة أثرية نادرة تمتد عبر آلاف السنين من عصر ما قبل التاريخ حتى الحقبة الإسلامية. تأسس المتحف عام 1926م بمبادرة من المستشارة البريطانية غيرترود بيل التي كرّست حياتها لصون الآثار العراقية. تضم قاعاته التحف السومرية والأكدية والبابلية والآشورية والإسلامية، ومن أبرز محتوياته: رأس المرأة الوركائية (الإلهة إنانا) المنحوتة قبل أربعة آلاف عام، وكنوز الأميرات من نمرود ذات الذهب الخالص، وألواح ملحمة كلكامش الطينية، والتمائم والأختام الأسطوانية. في عام 2003م تعرّض المتحف للنهب والتدمير، وفُقدت آلاف القطع الثمينة، غير أن الجهود الدولية استعادت الكثير منها وأعادت فتح أبوابه للزوار.',
    descriptionEn:'The Iraq Museum is one of the world\'s greatest museums and richest repositories of human history, holding more than 170,000 rare artifacts spanning thousands of years from prehistory to the Islamic era. It was founded in 1926 through the efforts of British advisor Gertrude Bell, who devoted her life to preserving Iraq\'s antiquities. Its halls house Sumerian, Akkadian, Babylonian, Assyrian, and Islamic treasures, including the Mask of Warka (a depiction of the goddess Inanna) carved four thousand years ago, the solid-gold treasures of the Nimrud princesses, the clay tablets of the Epic of Gilgamesh, and ancient amulets and cylinder seals. In 2003 the museum was looted and damaged, with thousands of priceless pieces lost, though international efforts have since recovered many of them and reopened its doors to visitors.',
    lat:33.3408, lng:44.3614, civilization:'متعددة', type:'متحف',
    civilizationEn:'Multiple', typeEn:'Museum',
    builtYear:'1926 م', builtYearEn:'1926 CE', imageUrl:'assets/images/landmarks/iraq_museum.jpg',
    isFeatured:true, tags:['متحف','آثار','بغداد','سومري','بابلي','آشوري']),

  Site(id:'s002', name:'طاق كسرى (إيوان كسرى)', nameEn:'Ctesiphon Arch',
    city:'المدائن', governorate:'بغداد', cityEn:'Al-Madain', governorateEn:'Baghdad',
    description:'طاق كسرى أو إيوان كسرى هو أحد أعظم وأضخم الأبنية المعمارية في التاريخ القديم، ويُمثّل الإرث المعماري للحضارة الساسانية في قلب بلاد الرافدين. يرتفع هذا القوس الهائل إلى نحو 37 متراً ويمتد عرضه 26 متراً، مما يجعله أكبر قوس طيني لم يُقبّب بعد في العالم حتى اليوم. شُيّد في القرن الرابع الميلادي إبان حكم الأسرة الساسانية ليكون الإيوان الملكي الرئيسي لعاصمتهم المدائن (تيسفون)، وكان يُستخدم قاعةً لاستقبال الملوك والسفراء. تُحيط بالإيوان جدران ضخمة مزخرفة بالآجر المنقوش وبقايا فسيفساء رائعة. شهدت المنطقة معركة القادسية الفاصلة عام 636م التي فتح فيها العرب المسلمون المدائن وأسقطوا الإمبراطورية الساسانية إلى الأبد.',
    descriptionEn:'The Ctesiphon Arch (Taq Kasra) is one of the greatest and largest architectural monuments of the ancient world, representing the Sasanian Empire\'s legacy in the heart of Mesopotamia. This colossal arch rises about 37 metres high and spans 26 metres wide, making it the largest unreinforced brick arch in the world to this day. Built in the 4th century CE under Sasanian rule, it served as the main royal hall of their capital, Ctesiphon, used to receive kings and ambassadors. Massive walls decorated with carved brick and remnants of exquisite mosaics surround the hall. The decisive Battle of al-Qadisiyyah took place nearby in 636 CE, when Muslim Arab forces conquered Ctesiphon and brought the Sasanian Empire to its final end.',
    lat:33.0955, lng:44.5804, civilization:'ساسانية', type:'قوس تاريخي',
    civilizationEn:'Sasanian', typeEn:'Historic Arch',
    builtYear:'القرن 4 م', builtYearEn:'4th century CE', imageUrl:'assets/images/landmarks/ctesiphon.jpg',
    isFeatured:true, tags:['ساساني','إيوان','مدائن','فارسي','معمار']),

  Site(id:'s003', name:'مدينة بابل الأثرية', nameEn:'Babylon',
    city:'الحلة', governorate:'بابل', cityEn:'Al-Hillah', governorateEn:'Babylon',
    description:'بابل، مدينة الأساطير والعظمة، كانت إحدى أعظم مدن العالم القديم وعاصمة الإمبراطورية البابلية في ذروة مجدها. يعود تاريخ المدينة إلى أكثر من أربعة آلاف عام، وقد بلغت أوج ازدهارها في عهد الملك نبوخذنصر الثاني (605-562 ق.م) الذي جعلها قبلة الدنيا. كانت المدينة تمتد على مساحة شاسعة تُحيط بها أسوار ضخمة متعددة الطبقات، وتخترقها شوارع مُرصّفة بالحجارة، وتزدان بزقوراتها الشاهقة ومعابدها الفاخرة. اشتُهرت بابل بعجيبتين من عجائب الدنيا السبع: حدائق بابل المعلقة التي شيّدها نبوخذنصر لزوجته الميدية، وبوابة عشتار المزيّنة بالتنانين والثيران اللازوردية. دخلها الإسكندر الأكبر فاتحاً عام 331 ق.م وتوفي فيها عام 323 ق.م. أُدرجت المدينة على قائمة التراث العالمي لليونسكو.',
    descriptionEn:'Babylon, city of legend and grandeur, was one of the greatest cities of the ancient world and capital of the Babylonian Empire at the height of its glory. Its history stretches back more than four thousand years, reaching its peak under King Nebuchadnezzar II (605–562 BCE), who made it the envy of the world. The city covered a vast area surrounded by massive multi-layered walls, with stone-paved streets and towering ziggurats and lavish temples. Babylon was famed for two of the Seven Wonders of the Ancient World: the Hanging Gardens, built by Nebuchadnezzar for his Median wife, and the Ishtar Gate, adorned with lapis-blue dragons and bulls. Alexander the Great entered the city as conqueror in 331 BCE and died there in 323 BCE. The site is inscribed on the UNESCO World Heritage List.',
    lat:32.5427, lng:44.4215, civilization:'بابلية', type:'مدينة أثرية',
    civilizationEn:'Babylonian', typeEn:'Archaeological City',
    builtYear:'~2000 ق.م', builtYearEn:'~2000 BCE', imageUrl:'assets/images/landmarks/babylon.jpg',
    isUnesco:true, isFeatured:true, tags:['بابل','عشتار','يونسكو','نبوخذنصر','حدائق معلقة']),

  Site(id:'s004', name:'بوابة عشتار', nameEn:'Ishtar Gate',
    city:'الحلة', governorate:'بابل', cityEn:'Al-Hillah', governorateEn:'Babylon',
    description:'بوابة عشتار هي الثامنة من بوابات مدينة بابل الأسطورية، وتُعدّ من أبدع وأجمل الإنجازات المعمارية في تاريخ الحضارات القديمة. شيّدها الملك نبوخذنصر الثاني حوالي عام 575 ق.م وأهداها إلى الإلهة عشتار إلهة الحب والحرب والخصب. تتألق البوابة بألواح من القرميد الأزرق اللازوردي اللامع المزيّن بتماثيل بارزة لحيوانات مقدسة: تنين ماردوك الأسطوري ذو الحراشف والقرون، وثور أداد إله العاصفة. كانت البوابة مدخلاً للطريق المقدس الذي يمتد على طول كيلومتر ونصف مُكتنَفاً بجدران من القرميد الأزرق المنقوش. اكتُشفت أجزاؤها الأصلية وأُعيد تركيبها في متحف برلين بألمانيا، فيما أُعيد بناء نسخة منها في موقع بابل ذاتها.',
    descriptionEn:'The Ishtar Gate was the eighth gate of legendary Babylon, and one of the most magnificent architectural achievements of the ancient world. Built by King Nebuchadnezzar II around 575 BCE, it was dedicated to Ishtar, goddess of love, war, and fertility. The gate gleams with glazed blue-lapis tiles adorned with relief figures of sacred animals: the mythical scaled and horned dragon of Marduk, and the bull of Adad, god of storms. It formed the entrance to the Processional Way, a kilometre-and-a-half-long avenue flanked by walls of decorated blue brick. The original fragments were excavated and reassembled in Berlin\'s Pergamon Museum, while a reconstructed replica now stands at the Babylon site itself.',
    lat:32.5415, lng:44.4210, civilization:'بابلية', type:'بوابة تاريخية',
    civilizationEn:'Babylonian', typeEn:'Historic Gate',
    builtYear:'575 ق.م', builtYearEn:'575 BCE', imageUrl:'assets/images/landmarks/ishtar_gate.jpg',
    isFeatured:true, tags:['بابل','عشتار','نبوخذنصر','بوابة','لازورد']),

  Site(id:'s007', name:'زقورة أور العظيمة', nameEn:'Great Ziggurat of Ur',
    city:'الناصرية', governorate:'ذي قار', cityEn:'Nasiriyah', governorateEn:'Dhi Qar',
    description:'تقف زقورة أور العظيمة شامخةً في صحراء جنوب العراق كشاهد حي على عبقرية المعماريين السومريين قبل أربعة آلاف سنة. شيّدها الملك أورنمو مؤسس أسرة أور الثالثة حوالي 2100 ق.م تقرّباً إلى الإله القمر نانا حامي مدينة أور. تتكون الزقورة من ثلاثة طوابق متراكبة يصل ارتفاعها الأصلي إلى نحو 21 متراً، وتمتد قاعدتها على مساحة 64 × 46 متراً. جُدرانها من الطين المحروق السميك المكسوة بطبقة من الآجر المشوي، وتعلوها منصة المعبد المخصصة لعبادة الإله القمر. اكتشفها المنقّب البريطاني ليونارد وولي في عشرينيات القرن الماضي واندهش بروعة حالتها التحفظية. أُدرجت ضمن مواقع التراث العالمي لليونسكو ضمن منطقة الأهوار والمدن الأثرية الجنوبية.',
    descriptionEn:'The Great Ziggurat of Ur stands tall in the deserts of southern Iraq as a living testament to the genius of Sumerian builders four thousand years ago. It was built by King Ur-Nammu, founder of the Third Dynasty of Ur, around 2100 BCE, in devotion to the moon god Nanna, patron of the city of Ur. The ziggurat rises in three stacked tiers to an original height of about 21 metres, with a base measuring 64 by 46 metres. Its walls are made of thick mud brick faced with fired brick, topped by a temple platform dedicated to the moon god\'s worship. British archaeologist Leonard Woolley rediscovered it in the 1920s and marvelled at its remarkable state of preservation. It is part of the UNESCO World Heritage inscription covering the southern marshlands and ancient cities.',
    lat:30.9626, lng:46.1033, civilization:'سومرية', type:'زقورة',
    civilizationEn:'Sumerian', typeEn:'Ziggurat',
    builtYear:'~2100 ق.م', builtYearEn:'~2100 BCE', imageUrl:'assets/images/landmarks/ziggurat_ur.jpg',
    isUnesco:true, isFeatured:true, tags:['سومر','زقورة','أور','يونسكو','أورنمو','نانا']),

  Site(id:'s011', name:'مدينة نينوى', nameEn:'Nineveh',
    city:'الموصل', governorate:'نينوى', cityEn:'Mosul', governorateEn:'Nineveh',
    description:'نينوى، عروس الشمال وعاصمة الإمبراطورية الآشورية في ذروة قوتها، كانت في القرن السابع قبل الميلاد أكبر مدينة في العالم المعروف بأسره. أحاط بها سور منيع يمتد 12 كيلومتراً ويخترقه 15 بوابة ضخمة تحرسها تماثيل اللاماسو الهائلة. أمر الملك سنحاريب ببناء قصره الأسطوري "القصر الذي لا مثيل له" المزيّن بـ71 غرفة كُسيت جدرانها بألواح حجرية منقوشة بمئات المشاهد الحربية والصيدية. وعلى بُعد خطوات منه شيّد حفيده آشور بانيبال مكتبة نينوى الشهيرة، أول مكتبة منظّمة في تاريخ البشرية. دمّر البابليون والميديون نينوى عام 612 ق.م، وأُدرجت على قائمة التراث العالمي المهدَّد بالخطر.',
    descriptionEn:'Nineveh, bride of the north and capital of the Assyrian Empire at its zenith, was in the 7th century BCE the largest city in the entire known world. It was ringed by a formidable 12-kilometre wall pierced by 15 great gates guarded by colossal lamassu statues. King Sennacherib commissioned his legendary "Palace Without Rival," adorned with 71 rooms whose walls were carved with hundreds of war and hunting scenes. Nearby, his grandson Ashurbanipal built the famous Library of Nineveh, the first organized library in human history. Nineveh was destroyed by the Babylonians and Medes in 612 BCE, and is listed as World Heritage in Danger.',
    lat:36.3610, lng:43.1565, civilization:'آشورية', type:'مدينة أثرية',
    civilizationEn:'Assyrian', typeEn:'Archaeological City',
    builtYear:'~700 ق.م', builtYearEn:'~700 BCE', imageUrl:'assets/images/landmarks/nineveh.jpg',
    isUnesco:true, isFeatured:true, tags:['آشور','نينوى','لاماسو','يونسكو','سنحاريب']),

  Site(id:'s015', name:'مدينة الحضر', nameEn:'Hatra',
    city:'الحضر', governorate:'نينوى', cityEn:'Hatra', governorateEn:'Nineveh',
    description:'الحضر مدينة الشمس والعرب، ملكة الصحراء الشمالية، قامت في القرن الأول الميلادي لتكون درّة حضارة المملكة الحضرية العربية المستقلة. تمتد على مساحة 324 هكتاراً وتُحيط بها أسوار دائرية ضخمة يبلغ قطرها نحو كيلومترين ونصف. يتصدّر قلبها مجمع المعابد الكبير (التيمينوس) الذي يجمع في معماره بين الطرازين الهلنستي والفارثي والعربي في تناغم استثنائي. زخرفت جدران معابدها بنقوش بارزة رائعة تصوّر الآلهة والملوك والمحاربين. صمدت المدينة أمام هجومَي الإمبراطور تراجان الروماني عامَي 116م و117م ورفضت الاستسلام. أُدرجت ضمن التراث العالمي لليونسكو.',
    descriptionEn:'Hatra, city of the sun and the Arabs, queen of the northern desert, rose in the 1st century CE as the jewel of an independent Arab kingdom. It covers 324 hectares, encircled by massive circular walls roughly two and a half kilometres in diameter. At its heart stands the great temple complex (Temenos), blending Hellenistic, Parthian, and Arab architectural styles in remarkable harmony. Its temple walls bear superb relief carvings of gods, kings, and warriors. The city withstood two assaults by the Roman emperor Trajan in 116 and 117 CE, refusing to surrender. It is inscribed on the UNESCO World Heritage List.',
    lat:35.5872, lng:42.7236, civilization:'حضرية', type:'مدينة أثرية',
    civilizationEn:'Hatran', typeEn:'Archaeological City',
    builtYear:'~100 م', builtYearEn:'~100 CE', imageUrl:'assets/images/landmarks/hatra.jpg',
    isUnesco:true, isFeatured:true, tags:['حضر','فرثي','عربي','يونسكو','معابد']),

  Site(id:'s017', name:'ملوية سامراء', nameEn:'Malwiya Minaret',
    city:'سامراء', governorate:'صلاح الدين', cityEn:'Samarra', governorateEn:'Saladin',
    description:'مئذنة الملوية في سامراء هي أيقونة العمارة الإسلامية بلا منازع، وواحدة من أكثر المعالم المعمارية أصالةً وتميزاً في العالم أجمع. بناها الخليفة العباسي المتوكل على الله بين عامَي 848 و852م لتكون مئذنة جامع سامراء الكبير الذي كان أضخم مسجد في العالم آنذاك. يرتفع هذا الصرح الهرمي اللولبي إلى 52 متراً بقطر قاعدة يبلغ 33 متراً، وتلتف حوله درجاته الخمس بشكل حلزوني صاعد من الخارج كأنه يتحدّى الجاذبية. الأسلوب المعماري الفريد ذو الشكل الحلزوني مستوحى على الأرجح من زقورات بلاد الرافدين القديمة، ما يجعله جسراً حضارياً رائعاً بين حضارتَين عظيمتَين.',
    descriptionEn:'The Malwiya Minaret of Samarra is an undisputed icon of Islamic architecture, one of the most original and distinctive landmarks in the world. Built by the Abbasid caliph al-Mutawakkil between 848 and 852 CE as the minaret of the Great Mosque of Samarra — the largest mosque in the world at the time — this spiralling pyramidal structure rises 52 metres with a base 33 metres across. Its five tiers wind upward in an external spiral ramp, as if defying gravity. The unique spiral design is thought to be inspired by the ancient ziggurats of Mesopotamia, making it a remarkable cultural bridge between two great civilizations.',
    lat:34.2098, lng:43.8756, civilization:'إسلامية', type:'مئذنة',
    civilizationEn:'Islamic', typeEn:'Minaret',
    builtYear:'848 م', builtYearEn:'848 CE', imageUrl:'assets/images/landmarks/malwiya.jpg',
    isUnesco:true, isFeatured:true, tags:['عباسي','مئذنة','سامراء','يونسكو','إسلامي']),

  Site(id:'s020', name:'مدينة آشور', nameEn:'Ashur',
    city:'القيارة', governorate:'نينوى', cityEn:'Qayyarah', governorateEn:'Nineveh',
    description:'آشور، أُمّ المدن الآشورية وقلبها الديني والروحي، كانت أقدم عاصمة للحضارة الآشورية وظلّت عبر ألفَي سنة المركز المقدس الذي يتوجّه إليه الآشوريون حيثما حلّوا. تقع على ضفة نهر دجلة الغربية فوق هضبة صخرية طبيعية محصّنة، وأُسِّست حوالي 2500 ق.م. كانت موطن الإله آشور رب الآلهة، وفيها تُقيم ملوك الآشوريين شعائر تتويجهم وفيها يُدفنون في مقابر ملكية منحوتة. تضم معبد الإله آشور الكبير ومجموعة من أكثر المعابد والقصور الآشورية قِدَماً. أُدرجت على قائمة التراث العالمي لليونسكو.',
    descriptionEn:'Ashur, mother of Assyrian cities and their religious and spiritual heart, was the oldest capital of Assyrian civilization, remaining for two thousand years the sacred centre that Assyrians turned to wherever they settled. Set on the western bank of the Tigris atop a fortified natural rocky plateau, it was founded around 2500 BCE. It was home to the god Ashur, lord of the gods, where Assyrian kings held their coronation rites and were buried in carved royal tombs. It contains the great temple of the god Ashur along with some of the oldest Assyrian temples and palaces. It is inscribed on the UNESCO World Heritage List.',
    lat:35.4566, lng:43.2597, civilization:'آشورية', type:'مدينة أثرية',
    civilizationEn:'Assyrian', typeEn:'Archaeological City',
    builtYear:'~2500 ق.م', builtYearEn:'~2500 BCE', imageUrl:'assets/images/landmarks/ashur.jpg',
    isUnesco:true, isFeatured:true, tags:['آشور','يونسكو','عاصمة','دجلة']),

  Site(id:'s024', name:'أوروك (الوركاء)', nameEn:'Uruk',
    city:'السماوة', governorate:'المثنى', cityEn:'Samawah', governorateEn:'Al-Muthanna',
    description:'أوروك أو الوركاء، مهد الحضارة الإنسانية وأول مدينة حقيقية في تاريخ البشرية، نشأت على ضفاف الفرات منذ أكثر من خمسة آلاف عام لتُعلن ميلاد عصر المدن. بلغت في ذروتها حوالي 3000 ق.م مساحةً تتجاوز 5.5 كيلومتر مربع وعدد سكان يناهز خمسين ألف نسمة، مما جعلها أكبر تجمّع بشري في العالم القديم. منها انبثقت الكتابة المسمارية أول مرة حوالي 3200 ق.م حين احتاج كتّاب المعابد لتسجيل معاملاتهم التجارية، فولدت بذلك فجر الحضارة الإنسانية المكتوبة. في أوروك تربّع الملك الأسطوري كلكامش على عرشه وشيّد أسوارها الأسطورية. أُدرجت على قائمة التراث العالمي لليونسكو.',
    descriptionEn:'Uruk, cradle of human civilization and the first true city in human history, rose on the banks of the Euphrates more than five thousand years ago, marking the birth of the urban age. At its peak around 3000 BCE it covered over 5.5 square kilometres with a population approaching fifty thousand, making it the largest human settlement in the ancient world. Cuneiform writing first emerged here around 3200 BCE, when temple scribes needed to record commercial transactions — the dawn of written human civilization. In Uruk, the legendary King Gilgamesh sat upon his throne and built its famous walls. It is inscribed on the UNESCO World Heritage List.',
    lat:31.3240, lng:45.6375, civilization:'سومرية', type:'مدينة أثرية',
    civilizationEn:'Sumerian', typeEn:'Archaeological City',
    builtYear:'~4000 ق.م', builtYearEn:'~4000 BCE', imageUrl:'assets/images/landmarks/uruk.jpg',
    isUnesco:true, isFeatured:true, tags:['سومر','كلكامش','أوروك','يونسكو','كتابة']),


  Site(id:'s044', name:'نمرود (كالخو)', nameEn:'Nimrud',
    city:'الموصل', governorate:'نينوى', cityEn:'Mosul', governorateEn:'Nineveh',
    description:'نمرود أو كالخو الآشورية، العاصمة الإمبراطورية الثانية للآشوريين، شُيّدت على ضفة دجلة بأمر من الملك آشورناصربال الثاني عام 880 ق.م ليجعل منها عاصمةً لأعظم إمبراطورية شهدها العالم القديم. أُعيد اكتشافها عام 1845م على يد المنقّب الإنجليزي أوستن هنري ليارد الذي أخرج من رحمها تماثيل اللاماسو الأسطورية الضخمة ونقوشها الحجرية التي تُزيّن اليوم متاحف برلين ولندن ونيويورك. في عام 1988م كشف علماء الآثار العراقيون عن كنز نمرود الأسطوري في قبور الأميرات الثلاث: مجموعة مذهلة من المجوهرات الذهبية تُقدَّر بما يزيد على نصف طن من الذهب الخالص. دمّر تنظيم داعش الإرهابي موقعها عام 2015م.',
    descriptionEn:'Nimrud, ancient Kalhu, the Assyrians\' second imperial capital, was built on the bank of the Tigris by order of King Ashurnasirpal II in 880 BCE to serve as capital of the greatest empire the ancient world had seen. It was rediscovered in 1845 by English excavator Austen Henry Layard, who unearthed colossal lamassu statues and stone reliefs that today adorn museums in Berlin, London, and New York. In 1988, Iraqi archaeologists uncovered the legendary Nimrud Treasure in the tombs of three princesses — a dazzling collection of gold jewellery weighing more than half a tonne of pure gold. The ISIS terrorist organization destroyed the site in 2015.',
    lat:36.0981, lng:43.3283, civilization:'آشورية', type:'مدينة أثرية',
    civilizationEn:'Assyrian', typeEn:'Archaeological City',
    builtYear:'~880 ق.م', builtYearEn:'~880 BCE', imageUrl:'assets/images/landmarks/nimrud.jpg',
    isFeatured:true, tags:['آشور','نمرود','لاماسو','كنوز','دجلة']),

  Site(id:'s059', name:'قلعة أربيل', nameEn:'Erbil Citadel',
    city:'أربيل', governorate:'أربيل', cityEn:'Erbil', governorateEn:'Erbil',
    description:'قلعة أربيل أو هولير هي واحدة من أقدم المدن المأهولة باستمرار على وجه الأرض منذ ما يزيد على ستة آلاف سنة دون انقطاع. تقوم المدينة العتيقة على تلٍّ اصطناعي يرتفع نحو 32 متراً فوق السهل المحيط، تراكمت طبقاته عبر آلاف السنين من السكن المتواصل. دوّن الملك الأشوري شلمانصر الأول في القرن الثالث عشر قبل الميلاد أن المدينة كانت مأهولة قبله بأمد طويل. قلعة أربيل اليوم هي مدينة عتيقة متكاملة تضمّ بيوتاً ومساجد وأسواقاً وأزقة تروي حضارة عريقة. أُدرجت على قائمة التراث العالمي لليونسكو.',
    descriptionEn:'Erbil Citadel, also known as Hawler, is one of the oldest continuously inhabited settlements on Earth, occupied for more than six thousand years without interruption. The ancient city sits atop an artificial mound rising about 32 metres above the surrounding plain, its layers built up over millennia of continuous habitation. Assyrian king Shalmaneser I recorded in the 13th century BCE that the city had already been inhabited long before his time. Today, Erbil Citadel is a fully intact old town of houses, mosques, markets, and alleyways narrating a long and storied civilization. It is inscribed on the UNESCO World Heritage List.',
    lat:36.1918, lng:44.0092, civilization:'متعددة', type:'قلعة',
    civilizationEn:'Multiple', typeEn:'Citadel',
    builtYear:'~4000 ق.م', builtYearEn:'~4000 BCE', imageUrl:'assets/images/landmarks/erbil_citadel.jpg',
    isUnesco:true, isFeatured:true, tags:['أربيل','كردستان','قلعة','يونسكو']),

  Site(id:'s062', name:'كهف شانيدار', nameEn:'Shanidar Cave',
    city:'أربيل', governorate:'أربيل', cityEn:'Erbil', governorateEn:'Erbil',
    description:'كهف شانيدار في جبال زاغروس الشمالية يحمل أسرار البشرية الأولى على هذه الأرض. اكتشف المنقّب الأمريكي رالف سوليكي عام 1957م في أعماقه بقايا عشرة هياكل عظمية لإنسان نياندرتال تعود إلى ما بين 35,000 و65,000 سنة مضت. المفاجأة المذهلة جاءت من التحليل المخبري الذي كشف أن أحد الهياكل (شانيدار 4) دُفن وحوله غزارة من حبوب اللقاح لأزهار ربيعية متعددة، مما أوحى لأول مرة أن إنسان نياندرتال كان يمارس طقوس الدفن وكان تربطه بالطبيعة علاقة وجدانية. هذا الاكتشاف غيّر نظرة العلماء جذرياً لهذا الإنسان البدائي.',
    descriptionEn:'Shanidar Cave, in the northern Zagros mountains, holds secrets of humanity\'s earliest presence on this land. In 1957, American excavator Ralph Solecki discovered the remains of ten Neanderthal skeletons deep within, dating back between 35,000 and 65,000 years. A remarkable find came from lab analysis showing one skeleton (Shanidar 4) was buried surrounded by abundant pollen from various spring flowers — the first evidence suggesting Neanderthals practiced burial rituals and held an emotional bond with nature. This discovery radically changed scientists\' view of this early human species.',
    lat:36.8344, lng:44.2222, civilization:'ما قبل التاريخ', type:'كهف تاريخي',
    civilizationEn:'Prehistoric', typeEn:'Historic Cave',
    builtYear:'~60,000 ق.م', builtYearEn:'~60,000 BCE', imageUrl:'assets/images/landmarks/shanidar_cave.jpg',
    isFeatured:true, tags:['نياندرتال','كهف','شانيدار','ما قبل التاريخ']),

  Site(id:'s054', name:'زقورة عقرقوف', nameEn:'Dur Kurigalzu',
    city:'بغداد', governorate:'بغداد', cityEn:'Baghdad', governorateEn:'Baghdad',
    description:'زقورة عقرقوف أو دور كوريغالزو هي بقية باقية من عاصمة الكاشيين الغامضين الذين حكموا بابل لأكثر من أربعة قرون (1595-1155 ق.م). تنتصب هذه الزقورة الضخمة على بُعد 30 كيلومتراً غرب بغداد كمحارب شامخ يتحدى قرون الزمن بقوة لافتة. يبلغ ارتفاع ما تبقّى منها نحو 57 متراً فوق السهل المحيط، وكانت في الأصل مشيّدة من الطين المحروق والآجر ويُقدَّر أن ارتفاعها الأصلي بلغ 80 متراً. قدّس الكاشيون في هذه الزقورة الإله إنليل، وكانت المدينة المحيطة بها تضم قصراً ملكياً فاخراً وهياكل دينية ومجمعات سكنية واسعة.',
    descriptionEn:'The Ziggurat of Aqar Quf, ancient Dur-Kurigalzu, is a surviving remnant of the capital of the enigmatic Kassites, who ruled Babylon for more than four centuries (1595–1155 BCE). This massive ziggurat stands 30 kilometres west of Baghdad like a towering sentinel defying the ages. What remains rises about 57 metres above the surrounding plain; it was originally built of mud brick and fired brick, with an estimated original height of 80 metres. The Kassites consecrated this ziggurat to the god Enlil, and the surrounding city included a lavish royal palace, religious structures, and extensive residential complexes.',
    lat:33.4167, lng:44.1667, civilization:'كاشية', type:'زقورة',
    civilizationEn:'Kassite', typeEn:'Ziggurat',
    builtYear:'~1400 ق.م', builtYearEn:'~1400 BCE', imageUrl:'assets/images/landmarks/aqarquf.jpg',
    isFeatured:true, tags:['كاشي','زقورة','عقرقوف','بغداد']),

  Site(id:'s084', name:'المدرسة المستنصرية', nameEn:'Al-Mustansiriyya',
    city:'بغداد', governorate:'بغداد', cityEn:'Baghdad', governorateEn:'Baghdad',
    description:'المدرسة المستنصرية في بغداد هي واحدة من أقدم الجامعات في العالم وأعرقها تاريخاً، وتُمثّل التاج الذهبي للتعليم في حضارة الإسلام الكلاسيكية. بنيت بأمر من الخليفة العباسي المستنصر بالله وافتُتحت رسمياً عام 1227م بإشراف مباشر من الخليفة نفسه. كانت تضم أربعة مذاهب فقهية في وقت واحد، وتوفّر لطلابها السكن والطعام والرعاية الصحية مجاناً، وكان في رحابها دار كتب ضخمة ومستوصف طبي. صمدت أمام الغزو المغولي لبغداد عام 1258م واستمر التدريس فيها. لا تزال قائمة على ضفة دجلة في قلب بغداد التاريخية تستقبل الزوار.',
    descriptionEn:'Al-Mustansiriyya School in Baghdad is one of the oldest and most venerable universities in the world, representing the golden crown of education in classical Islamic civilization. It was built by order of the Abbasid caliph al-Mustansir and officially opened in 1227 CE under his direct supervision. It housed all four schools of Islamic jurisprudence at once, provided students with free housing, food, and healthcare, and contained a vast library and medical clinic. It survived the Mongol invasion of Baghdad in 1258 and teaching continued within its walls. It still stands on the bank of the Tigris in the heart of historic Baghdad, welcoming visitors today.',
    lat:33.3412, lng:44.3978, civilization:'إسلامية', type:'معلم تعليمي',
    civilizationEn:'Islamic', typeEn:'Educational Landmark',
    builtYear:'1227 م', builtYearEn:'1227 CE', imageUrl:'assets/images/landmarks/mustansiriyya.jpg',
    isFeatured:true, tags:['عباسي','بغداد','جامعة','علم','تعليم']),

  Site(id:'s048', name:'قصر الأخيضر', nameEn:'Ukhaidir Palace',
    city:'كربلاء', governorate:'كربلاء', cityEn:'Karbala', governorateEn:'Karbala',
    description:'قصر الأخيضر الصحراوي هو درّة العمارة الإسلامية المبكرة ومتحف مفتوح للفن المعماري العباسي في أوج إبداعه. يقع هذا الحصن الضخم على بُعد نحو 50 كيلومتراً جنوب غرب كربلاء في قلب الصحراء الغربية. بُني حوالي عام 775م ويُنسب إلى عيسى بن موسى أحد أمراء الأسرة العباسية. يمتد القصر على مساحة 175 × 169 متراً محاطاً بأسوار شاهقة وأبراج متعددة يمكن مشاهدتها من مسافات بعيدة. يكشف تصميمه عن حلول معمارية مبتكرة للتكيّف مع حرارة الصحراء: بدءاً من الأفنية الداخلية المتعددة وانتهاءً بنظام التهوية الذكي في الأسقف والجدران.',
    descriptionEn:'Ukhaidir Palace is a jewel of early Islamic architecture, an open-air museum of Abbasid architectural art at its creative peak. This massive fortress lies about 50 kilometres southwest of Karbala in the heart of the western desert. Built around 775 CE, it is attributed to Isa ibn Musa, a prince of the Abbasid dynasty. The palace spans 175 by 169 metres, surrounded by towering walls and numerous towers visible from afar. Its design reveals innovative architectural solutions for coping with desert heat — from multiple interior courtyards to a clever ventilation system built into its ceilings and walls.',
    lat:32.4517, lng:43.5895, civilization:'إسلامية', type:'قصر تاريخي',
    civilizationEn:'Islamic', typeEn:'Historic Palace',
    builtYear:'~775 م', builtYearEn:'~775 CE', imageUrl:'assets/images/landmarks/ukhaidir.jpg',
    isUnesco:true, tags:['عباسي','قصر','أخيضر','صحراء']),

  Site(id:'s031', name:'نيبور', nameEn:'Nippur',
    city:'الديوانية', governorate:'القادسية', cityEn:'Diwaniyah', governorateEn:'Al-Qadisiyyah',
    description:'نيبور، قبلة الآلهة ومحجّ الإنسانية القديمة، كانت المركز الديني الأعلى لحضارة بلاد الرافدين طوال ثلاثة آلاف سنة متواصلة دون أن تفقد قدسيتها أو مكانتها. في هذه المدينة المقدسة قطن الإله إنليل سيد الآلهة السومريين، وكان الملك الذي يحظى بمباركته يحصل على شرعية حكم بلاد الرافدين كلها. كانت نيبور مركزاً للتعليم والكتابة والعلوم، وقد وجد المنقّبون الأمريكيون فيها أكثر من ثلاثين ألف لوح طيني تحمل نصوصاً دينية وأدبية وعلمية وإدارية. يعود الاستيطان فيها إلى ما قبل خمسة آلاف عام.',
    descriptionEn:'Nippur, sacred centre of the gods and pilgrimage site of the ancient world, was the supreme religious centre of Mesopotamian civilization for three thousand uninterrupted years, never losing its sanctity or standing. This holy city was home to the god Enlil, chief of the Sumerian gods, and any king who won his blessing gained legitimacy to rule all of Mesopotamia. Nippur was a centre of learning, writing, and science; American excavators found more than thirty thousand clay tablets there bearing religious, literary, scientific, and administrative texts. Settlement here dates back more than five thousand years.',
    lat:32.1264, lng:45.2317, civilization:'سومرية', type:'مدينة أثرية',
    civilizationEn:'Sumerian', typeEn:'Archaeological City',
    builtYear:'~5000 ق.م', builtYearEn:'~5000 BCE', imageUrl:'assets/images/landmarks/nippur.jpg',
    isUnesco:true, tags:['سومر','نيبور','إنليل','ديني']),

  Site(id:'s095', name:'أهوار جنوب العراق', nameEn:'Iraqi Marshlands',
    city:'البصرة', governorate:'البصرة', cityEn:'Basra', governorateEn:'Basra',
    description:'أهوار جنوب العراق هي الجنة المنسية وموطن أقدم حضارة بشرية مستمرة على وجه الأرض. تمتد هذه البيئة المائية الفريدة بين نهرَي دجلة والفرات على مساحة تتجاوز عشرة آلاف كيلومتر مربع في أوقات الفيضان. سكن هذه الأهوار إنسان العصر الحجري منذ ستة آلاف سنة، ثم جاء السومريون وشيّدوا مدنهم الأولى على حوافها. يعيش فيها اليوم عرب الأهوار (المعدان) في منازل مبنية على الجزر الصناعية من القصب والبردي، متواصلين مع أسلوب حياة لم يتغير منذ آلاف السنين. أُدرجت الأهوار وخمس مدن أثرية محيطة بها ضمن التراث العالمي لليونسكو عام 2016م.',
    descriptionEn:'The Marshlands of southern Iraq are a forgotten paradise and home to the oldest continuously inhabited human culture on Earth. This unique wetland environment spans more than ten thousand square kilometres between the Tigris and Euphrates rivers at flood times. Stone Age humans settled these marshes six thousand years ago, and later the Sumerians built their first cities along their edges. Today the Marsh Arabs (Ma\'dan) live here in homes built on artificial islands of reed and papyrus, continuing a way of life unchanged for thousands of years. The marshlands and five surrounding archaeological cities were inscribed on the UNESCO World Heritage List in 2016.',
    lat:30.8000, lng:47.1000, civilization:'سومرية', type:'موقع طبيعي أثري',
    civilizationEn:'Sumerian', typeEn:'Natural & Archaeological Site',
    builtYear:'~5000 ق.م', builtYearEn:'~5000 BCE', imageUrl:'assets/images/landmarks/marshlands.jpg',
    isUnesco:true, isFeatured:true, tags:['سومر','أهوار','بصرة','يونسكو','طبيعة']),

  // ══ مراقد أهل البيت ع ══════════════════════════════════
  Site(id:'sh001', name:'مرقد الإمام الحسين ع', nameEn:'Imam Hussein Shrine',
    city:'كربلاء المقدسة', governorate:'كربلاء', cityEn:'Holy Karbala', governorateEn:'Karbala',
    description:'مرقد الإمام الحسين بن علي في كربلاء المقدسة هو أقدس وأعظم مراقد أهل البيت عليهم السلام في العراق والعالم الإسلامي، ويستقطب الملايين من الزوار يومياً من شتى أنحاء العالم. يقوم المرقد على البقعة التي سقط فيها الإمام الحسين شهيداً يوم عاشوراء العاشر من محرم عام 61 هـ (680م). تعلو الضريح قبة ذهبية لامعة يبلغ ارتفاعها 27 متراً ويحيط بها مئذنتان ذهبيتان فارعتا الارتفاع، وتكتسي جدران الروضة بالمرايا الفضية المعشّقة والآيات القرآنية الكريمة المذهّبة.',
    descriptionEn:'The Shrine of Imam Hussein ibn Ali in Holy Karbala is the holiest and greatest shrine of the Prophet\'s household in Iraq and the Islamic world, drawing millions of visitors daily from around the globe. It stands on the very spot where Imam Hussein fell as a martyr on the Day of Ashura, the 10th of Muharram, 61 AH (680 CE). The tomb is topped by a gleaming golden dome 27 metres high, flanked by two soaring golden minarets, while the inner shrine\'s walls are inlaid with silver mirror-mosaics and gilded Quranic verses.',
    lat:32.6165, lng:44.0331, civilization:'إسلامية', type:'مرقد مقدس',
    civilizationEn:'Islamic', typeEn:'Holy Shrine',
    builtYear:'685 م', builtYearEn:'685 CE', imageUrl:'assets/images/landmarks/hussein_shrine.jpg',
    isFeatured:true, tags:['كربلاء','الحسين','عاشوراء','الأربعين','مرقد','أهل البيت']),

  Site(id:'sh002', name:'مرقد الإمام العباس ع', nameEn:'Imam Abbas Shrine',
    city:'كربلاء المقدسة', governorate:'كربلاء', cityEn:'Holy Karbala', governorateEn:'Karbala',
    description:'مرقد أبي الفضل العباس بن علي بن أبي طالب، قمر بني هاشم، يقع في كربلاء المقدسة مقابل مرقد أخيه الإمام الحسين على بُعد 400 متر. يتميز المرقد بقبته الذهبية البديعة ومئذنتيه الشامختين وصحنه الرحب المكسوّ بالرخام الأبيض. يُعدّ المرقد من أجمل التحف المعمارية الإسلامية في العالم، وتزداد قيمته الروحية لارتباطه بذكرى أبي الفضل الذي قُطعت يداه وهو يحمل الماء لأطفال الحسين.',
    descriptionEn:'The Shrine of Abu al-Fadl al-Abbas ibn Ali ibn Abi Talib, the "Moon of the Hashemites," stands in Holy Karbala facing his brother Imam Hussein\'s shrine, 400 metres away. It features a magnificent golden dome, two soaring minarets, and a spacious courtyard clad in white marble. The shrine is regarded as one of the most beautiful pieces of Islamic architecture in the world, its spiritual weight heightened by the memory of Abu al-Fadl, whose hands were severed as he carried water to Hussein\'s children.',
    lat:32.6172, lng:44.0342, civilization:'إسلامية', type:'مرقد مقدس',
    civilizationEn:'Islamic', typeEn:'Holy Shrine',
    builtYear:'~700 م', builtYearEn:'~700 CE', imageUrl:'assets/images/landmarks/abbas_shrine.jpg',
    isFeatured:true, tags:['كربلاء','العباس','أبو الفضل','مرقد','أهل البيت']),

  Site(id:'sh003', name:'مرقد الإمام علي ع — النجف', nameEn:'Imam Ali Shrine',
    city:'النجف الأشرف', governorate:'النجف', cityEn:'Najaf', governorateEn:'Najaf',
    description:'مرقد أمير المؤمنين الإمام علي بن أبي طالب في النجف الأشرف يُعدّ من أقدس البقاع على وجه الأرض عند المسلمين الشيعة وكثير من السنة. تعلوه قبة ذهبية ساطعة ترى لمسافات بعيدة وتُطوّقها مآذن ذهبية أربع فارعة الجمال. تكتسي جدران الروضة الداخلية بالمرايا والقرميد الفاخر وتحف الأبواب بالفضة المنقوشة. يُحيط بالمرقد الصحن الكبير المزيّن بالفسيفساء الإسلامية. النجف بأسرها مدينة علم ودين ومعرفة، تحتضن الحوزة العلمية الكبرى — أقدم الجامعات الدينية في العالم الإسلامي.',
    descriptionEn:'The Shrine of Imam Ali ibn Abi Talib, Commander of the Faithful, in Najaf is regarded as one of the holiest sites on Earth for Shia Muslims and many Sunnis alike. It is topped by a brilliant golden dome visible from afar, ringed by four exquisite golden minarets. The inner shrine\'s walls are inlaid with mirrors and fine tilework, its doors adorned with engraved silver. A great courtyard decorated with Islamic mosaics surrounds the shrine. Najaf as a whole is a city of learning, faith, and knowledge, home to the Great Hawza — the oldest religious seminary in the Islamic world.',
    lat:32.0008, lng:44.3158, civilization:'إسلامية', type:'مرقد مقدس',
    civilizationEn:'Islamic', typeEn:'Holy Shrine',
    builtYear:'~977 م', builtYearEn:'~977 CE', imageUrl:'assets/images/landmarks/imam_ali_shrine.jpg',
    isFeatured:true, tags:['النجف','الإمام علي','مرقد','أهل البيت','الحوزة العلمية']),

  Site(id:'sh004', name:'مرقد الإمام الكاظم والجواد ع — الكاظمية', nameEn:'Al-Kadhimiya Shrine',
    city:'الكاظمية — بغداد', governorate:'بغداد', cityEn:'Al-Kadhimiya, Baghdad', governorateEn:'Baghdad',
    description:'مرقد الإمامين الكاظمَين — موسى بن جعفر الكاظم ومحمد بن علي الجواد — في الكاظمية ببغداد يُعدّ من أبرز وأجمل المراقد الإسلامية في العالم. يتميز بقبتيه الذهبيتين المتلألئتين الشاهقتين اللتين تُزيّنان أفق بغداد ومئذنتيه الأربع الذهبية. يعود تاريخ البناء إلى أواخر القرن الثامن الميلادي وجرى على مرّ القرون توسيع وترميم الروضة حتى بلغت اليوم أبعادها الضخمة.',
    descriptionEn:'The Shrine of the two Kadhimi Imams — Musa ibn Ja\'far al-Kadhim and Muhammad ibn Ali al-Jawad — in Al-Kadhimiya, Baghdad, is among the most prominent and beautiful Islamic shrines in the world. It features two soaring, glittering golden domes that adorn Baghdad\'s skyline, along with four golden minarets. Construction dates back to the late 8th century CE, and the shrine has been expanded and restored over the centuries to reach its grand scale today.',
    lat:33.3788, lng:44.3394, civilization:'إسلامية', type:'مرقد مقدس',
    civilizationEn:'Islamic', typeEn:'Holy Shrine',
    builtYear:'~800 م', builtYearEn:'~800 CE', imageUrl:'assets/images/landmarks/kadhimiya_shrine.jpg',
    isFeatured:true, tags:['الكاظمية','بغداد','الكاظم','الجواد','مرقد','أهل البيت']),

  Site(id:'sh005', name:'مرقد الإمامَين العسكريَّين — سامراء', nameEn:'Al-Askari Shrine',
    city:'سامراء', governorate:'صلاح الدين', cityEn:'Samarra', governorateEn:'Saladin',
    description:'مرقد الإمامين العسكريَّين — علي الهادي والحسن العسكري — في سامراء هو أحد أقدس المواقع الإسلامية في العالم عند الشيعة. اشتُهر المرقد بقبته الذهبية الكبيرة التي كانت آية في الجمال قبل أن تفجّرها المتفجرات عام 2006م، ثم أُعيد بناؤها وأُعيد تذهيبها بجهود دولية. يضم المرقد أيضاً بجواره سرداب الغيبة المرتبط بالإمام الثاني عشر المهدي المنتظر.',
    descriptionEn:'The Shrine of the two Askari Imams — Ali al-Hadi and Hassan al-Askari — in Samarra is one of the holiest Islamic sites in the world for Shia Muslims. The shrine was famed for its great golden dome, a marvel of beauty, before it was bombed in 2006; it was later rebuilt and re-gilded through international efforts. Adjacent to the shrine lies the Cellar of the Disappearance, linked to the Twelfth Imam, al-Mahdi al-Muntazar.',
    lat:34.1983, lng:43.8720, civilization:'إسلامية', type:'مرقد مقدس',
    civilizationEn:'Islamic', typeEn:'Holy Shrine',
    builtYear:'~900 م', builtYearEn:'~900 CE', imageUrl:'assets/images/landmarks/askari_shrine.jpg',
    isFeatured:true, tags:['سامراء','العسكريَّين','الهادي','العسكري','مرقد','أهل البيت']),

  Site(id:'sh007', name:'وادي السلام — النجف', nameEn:'Wadi Al-Salam Cemetery',
    city:'النجف الأشرف', governorate:'النجف', cityEn:'Najaf', governorateEn:'Najaf',
    description:'وادي السلام في النجف الأشرف هو أكبر مقبرة في العالم من حيث المساحة والكثافة، إذ تمتد على نحو 917 هكتاراً وتضم رفات أكثر من خمسة ملايين شخص. يعود تاريخها إلى أكثر من 1400 عام وتتواصل الدفنات فيها حتى اليوم. يتمنى ملايين المسلمين حول العالم أن يُدفنوا في جوار مرقد الإمام علي.',
    descriptionEn:'Wadi Al-Salam in Najaf is the largest cemetery in the world by area and density, spanning roughly 917 hectares and holding the remains of more than five million people. Its history stretches back over 1,400 years, and burials continue there to this day. Millions of Muslims around the world wish to be laid to rest near the Shrine of Imam Ali.',
    lat:31.9965, lng:44.3108, civilization:'إسلامية', type:'موقع تراثي',
    civilizationEn:'Islamic', typeEn:'Heritage Site',
    builtYear:'القرن 7 م', builtYearEn:'7th century CE', imageUrl:'assets/images/landmarks/wadi_salam.jpg',
    isFeatured:false, tags:['النجف','وادي السلام','مقبرة','تراث إسلامي']),
];

const List<HistoricalCharacter> iraqCharacters = [

  HistoricalCharacter(id:'c001', name:'كلكامش', nameEn:'Gilgamesh',
    era:'~2700 ق.م', civilization:'سومرية', role:'ملك أوروك وبطل الملحمة الخالدة',
    eraEn:'~2700 BCE', civilizationEn:'Sumerian', roleEn:'King of Uruk and Hero of the Eternal Epic',
    description:'كلكامش ملك مدينة أوروك السومرية وبطل أقدم وأعظم ملحمة أدبية كتبها الإنسان في التاريخ. تصفه الملحمة بأنه ابن الإلهة نينسون وشبه إله، نسيجه خمسة أثمان إلهية وثلاثة أثمان بشرية. حكم أوروك بيد من حديد وبنى أسوارها الأسطورية من اللبن المشوي. حين مات صديقه الحميم إنكيدو الذي أحبّه كنفسه، أُصيب كلكامش برعب الموت فانطلق في رحلة مضنية يبحث عن سر الخلود في أعماق الأرض وخلف مياه الموت حيث يقيم الخالد أوتنابشتيم. أخفق في نهاية المطاف لكن رحلته خلّدت اسمه وأبدعت تحفة أدبية تُدرَّس اليوم في جامعات العالم.',
    descriptionEn:'Gilgamesh, king of the Sumerian city of Uruk, is the hero of the oldest and greatest work of literature ever written by humankind. The epic describes him as the son of the goddess Ninsun and part divine, his being five-eighths god and three-eighths human. He ruled Uruk with an iron fist and built its legendary walls of fired brick. When his intimate friend Enkidu, whom he loved as himself, died, Gilgamesh was struck with terror of death and set out on an arduous journey seeking the secret of immortality, deep within the earth and beyond the waters of death where the immortal Utnapishtim dwelt. He ultimately failed, but his journey immortalized his name and produced a literary masterpiece still taught in universities worldwide today.',
    imageUrl:'assets/images/characters/gilgamesh.jpg',
    birthYear:'~2750 ق.م', deathYear:'~2700 ق.م',
    birthYearEn:'~2750 BCE', deathYearEn:'~2700 BCE',
    achievements:['بناء أسوار أوروك الأسطورية','ملحمة كلكامش أقدم أدب إنساني','رحلة البحث عن الخلود','فتح غابة الأرز وقتل هومبابا','رفض حب الإلهة عشتار'],
    achievementsEn:['Built the legendary walls of Uruk','The Epic of Gilgamesh — humanity\'s oldest literature','Undertook a quest for immortality','Conquered the Cedar Forest and slew Humbaba','Rejected the love of the goddess Ishtar']),

  HistoricalCharacter(id:'c002', name:'سرجون الأكدي', nameEn:'Sargon of Akkad',
    era:'~2334-2279 ق.م', civilization:'أكدية', role:'مؤسس أول إمبراطورية في التاريخ',
    eraEn:'~2334–2279 BCE', civilizationEn:'Akkadian', roleEn:'Founder of History\'s First Empire',
    description:'سرجون الأكدي أحد أعظم القادة الذين أنجبهم التاريخ البشري، وصاحب أعجب قصة صعود من الصفر إلى القمة. وُلد مجهول النسب بحسب الأسطورة إذ وضعته أمه في سلة قصب وأطلقتها في نهر الفرات فالتقطه ربّاه مزارع بسيط. خدم في بلاط ملك كيش ساقياً ثم تدرّج حتى استولى على الحكم وأسّس إمبراطوريته. امتدت إمبراطوريته من جبال زاغروس شرقاً حتى البحر الأبيض المتوسط غرباً ومن الخليج العربي جنوباً حتى جبال طوروس شمالاً. أسّس جيشاً دائماً من 5,400 محارب لا يتركونه حتى في وجبات الطعام. حكم 56 عاماً وتركت إمبراطوريته بصمة لا تُمحى في تاريخ البشرية.',
    descriptionEn:'Sargon of Akkad was one of the greatest leaders human history has produced, with one of its most astonishing rags-to-riches stories. Legend says he was born of unknown parentage, set adrift in a reed basket on the Euphrates by his mother, and raised by a simple gardener. He served as a cupbearer at the court of the king of Kish before rising through the ranks to seize power and found his own empire. His realm stretched from the Zagros Mountains in the east to the Mediterranean Sea in the west, and from the Arabian Gulf in the south to the Taurus Mountains in the north. He established a standing army of 5,400 warriors who never left his side, even at meals. He reigned for 56 years, leaving an indelible mark on human history.',
    imageUrl:'assets/images/characters/sargon.jpg',
    birthYear:'~2334 ق.م', deathYear:'~2279 ق.م',
    birthYearEn:'~2334 BCE', deathYearEn:'~2279 BCE',
    achievements:['تأسيس الإمبراطورية الأكدية أول إمبراطورية بالتاريخ','توحيد بلاد الرافدين بالكامل','فتح 34 مدينة في حملة واحدة','إنشاء أول جيش نظامي دائم','بناء عاصمة أكد الأسطورية'],
    achievementsEn:['Founded the Akkadian Empire — history\'s first empire','Fully unified Mesopotamia','Conquered 34 cities in a single campaign','Created the first standing professional army','Built the legendary capital of Akkad']),

  HistoricalCharacter(id:'c003', name:'نبوخذنصر الثاني', nameEn:'Nebuchadnezzar II',
    era:'605-562 ق.م', civilization:'بابلية', role:'ملك بابل العظيم وباني العجائب',
    eraEn:'605–562 BCE', civilizationEn:'Babylonian', roleEn:'Great King of Babylon, Builder of Wonders',
    description:'نبوخذنصر الثاني أعظم ملوك الإمبراطورية البابلية الجديدة وأكثرهم شهرةً في التاريخ، حكم نصف قرن تقريباً جعل فيه بابل عاصمة العالم ومبهجة الأرض. ورث عرش أبيه نبوبلاصر عام 605 ق.م وفي يده انتصار قادش الباهر على مصر. أعاد بناء بابل من الأساس وضخّ في تشييد آثارها ثروات الشرق والغرب، فشيّد بوابة عشتار الخالدة وأعاد بناء الزقورة الكبرى وجدّد معبد مردوك وفتح شارع الموكب المُبهر. أمر ببناء حدائق بابل المعلقة هدية رومانسية لزوجته الأميرة الميدية أميتيس التي حنّت إلى جبال بلادها الخضراء. في عام 586 ق.م هدم هيكل سليمان في القدس وسبى اليهود إلى بابل.',
    descriptionEn:'Nebuchadnezzar II, greatest king of the Neo-Babylonian Empire and the most famous in history, reigned for nearly half a century, during which he made Babylon the capital of the world and the delight of the earth. He inherited his father Nabopolassar\'s throne in 605 BCE, fresh from a stunning victory over Egypt at Carchemish. He rebuilt Babylon from the ground up, pouring the wealth of east and west into its monuments: he built the eternal Ishtar Gate, rebuilt the Great Ziggurat, renovated the temple of Marduk, and opened the magnificent Processional Way. He commissioned the Hanging Gardens of Babylon as a romantic gift for his Median princess wife Amytis, who longed for the green mountains of her homeland. In 586 BCE he destroyed Solomon\'s Temple in Jerusalem and exiled the Jews to Babylon.',
    imageUrl:'assets/images/characters/nebuchadnezzar.jpg',
    birthYear:'~634 ق.م', deathYear:'562 ق.م',
    birthYearEn:'~634 BCE', deathYearEn:'562 BCE',
    achievements:['بناء حدائق بابل المعلقة إحدى عجائب الدنيا السبع','تشييد بوابة عشتار الأسطورية','إعادة بناء مدينة بابل كاملة','فتح مصر وهزيمتها في معركة كرخميش','تدمير هيكل سليمان وسبي اليهود'],
    achievementsEn:['Built the Hanging Gardens of Babylon, one of the Seven Wonders','Constructed the legendary Ishtar Gate','Rebuilt the entire city of Babylon','Defeated Egypt at the Battle of Carchemish','Destroyed Solomon\'s Temple and exiled the Jews to Babylon']),

  HistoricalCharacter(id:'c004', name:'حمورابي', nameEn:'Hammurabi',
    era:'1792-1750 ق.م', civilization:'بابلية', role:'الملك المشرّع وأبو القانون',
    eraEn:'1792–1750 BCE', civilizationEn:'Babylonian', roleEn:'The Lawgiver King, Father of Law',
    description:'حمورابي ملك بابل العظيم الذي رفع اسمها إلى القمة وخلّد ذكراه في التاريخ بعمل واحد غيّر مسار الحضارة الإنسانية إلى الأبد: قانونه الشهير. وصل إلى العرش عام 1792 ق.م وخاض حروباً موفّقة حتى وحّد بلاد الرافدين كلها تحت قبضته. في السنة الثانية والثلاثين من حكمه أمر بنقش مجموعة قوانينه الـ282 على مسلّة من الديوريت الأسود ارتفاعها مترين ونصف. تشمل قوانينه مسائل الزواج والطلاق والتبنّي والإرث والتجارة والأجور والعقوبات. استُنهضت هذه القوانين من رقادها عام 1901م حين اكتشف الفرنسيون المسلّة في إيران وأودعوها متحف اللوفر. أثّر قانون حمورابي على التشريعات البشرية اللاحقة حتى يومنا هذا.',
    descriptionEn:'Hammurabi, the great king of Babylon, raised the city to its peak and immortalized his name in history with a single achievement that changed the course of human civilization forever: his famous law code. He came to the throne in 1792 BCE and waged successful wars until he united all of Mesopotamia under his rule. In the thirty-second year of his reign, he ordered his 282 laws inscribed on a black diorite stele two and a half metres tall. His laws covered marriage, divorce, adoption, inheritance, trade, wages, and punishments. The code was rediscovered in 1901 when French archaeologists found the stele in Iran and placed it in the Louvre Museum. Hammurabi\'s Code influenced human legislation for centuries to come, right up to the present day.',
    imageUrl:'assets/images/characters/hammurabi.jpg',
    birthYear:'~1810 ق.م', deathYear:'1750 ق.م',
    birthYearEn:'~1810 BCE', deathYearEn:'1750 BCE',
    achievements:['سنّ قانون حمورابي أقدم قانون مدوّن متكامل','توحيد بلاد الرافدين تحت حكم بابل','إصلاح منظومة الضرائب والأجور','بناء معبد مردوك العظيم','تطوير التجارة والاقتصاد البابلي'],
    achievementsEn:['Enacted the Code of Hammurabi, the oldest complete written law code','United all of Mesopotamia under Babylonian rule','Reformed the tax and wage system','Built the great Temple of Marduk','Developed Babylonian trade and economy']),

  HistoricalCharacter(id:'c005', name:'آشور بانيبال', nameEn:'Ashurbanipal',
    era:'668-627 ق.م', civilization:'آشورية', role:'ملك المعرفة وجامع حكمة الأولين',
    eraEn:'668–627 BCE', civilizationEn:'Assyrian', roleEn:'King of Knowledge, Collector of Ancient Wisdom',
    description:'آشور بانيبال آخر ملوك الإمبراطورية الآشورية العظماء وأغربهم في التاريخ: محارب لا يُقهر وعالم مثقف وشاعر مرهف في شخصية واحدة. في عهده بلغت الإمبراطورية الآشورية أقصى امتداداتها حين ضمّ مصر إليها عام 667 ق.م. لكن شغفه الحقيقي كان المعرفة؛ أرسل رسله إلى كل أنحاء الشرق الأدنى يجمعون الألواح الطينية وينسخون النصوص القديمة. أسّس في نينوى مكتبة ملكية ضخمة احتوت على أكثر من 30,000 لوح طيني تضم رصيداً معرفياً هائلاً من الأدب والعلم والطقوس والتاريخ. وصف نفسه بأنه "يُتقن كل فنون الكتابة ويقرأ حجارة الزمن الغابر". بفضله وصلت إلينا ملحمة كلكامش.',
    descriptionEn:'Ashurbanipal, the last of the great Assyrian Empire\'s kings and one of the most remarkable figures in history, was an unbeatable warrior, a learned scholar, and a refined poet all in one. Under his rule the Assyrian Empire reached its greatest extent, annexing Egypt in 667 BCE. Yet his true passion was knowledge; he sent envoys throughout the Near East to collect clay tablets and copy ancient texts. He founded a vast royal library in Nineveh containing more than 30,000 clay tablets, an enormous store of literature, science, ritual, and history. He described himself as one who "mastered every art of writing and could read the stones of bygone ages." Thanks to him, the Epic of Gilgamesh survives to this day.',
    imageUrl:'assets/images/characters/ashurbanipal.jpg',
    birthYear:'~685 ق.م', deathYear:'~627 ق.م',
    birthYearEn:'~685 BCE', deathYearEn:'~627 BCE',
    achievements:['تأسيس مكتبة نينوى أول مكتبة منظّمة في التاريخ','جمع أكثر من 30,000 لوح طيني','غزو مصر وتوحيد الشرق الأدنى','الحفاظ على ملحمة كلكامش للأجيال','كان أول ملك متعلم يُتقن القراءة والكتابة'],
    achievementsEn:['Founded the Library of Nineveh, history\'s first organized library','Amassed over 30,000 clay tablets','Conquered Egypt and unified the Near East','Preserved the Epic of Gilgamesh for future generations','One of the first literate kings, skilled in reading and writing']),

  HistoricalCharacter(id:'c006', name:'سنحاريب', nameEn:'Sennacherib',
    era:'704-681 ق.م', civilization:'آشورية', role:'ملك آشور وباني نينوى الأعجوبة',
    eraEn:'704–681 BCE', civilizationEn:'Assyrian', roleEn:'King of Assyria, Builder of Wondrous Nineveh',
    description:'سنحاريب الملك الآشوري المثير للجدل الذي كان في الوقت ذاته محارباً قاسياً بلا رحمة ومعمارياً عبقرياً بلا مثيل. أعلى أعماله الحربية صدّه للحملات المصرية وتدميره لمدينة بابل المقدسة الأمر الذي استنكره عليه كثيرون. لكن في نينوى كتب أمجاده الحقيقية؛ حوّلها من مجرد مدينة إلى أعجوبة الدنيا. شيّد "القصر الذي لا مثيل له" في التاريخ: إثنا وثمانون غرفة كُسيت جدرانها بألواح حجرية نقش عليها آلاف المشاهد الحربية والصيدية والطقوسية بدقة مذهلة. حفر قناة مائية طولها خمسون كيلومتراً لري حدائق نينوى.',
    descriptionEn:'Sennacherib was a controversial Assyrian king who was at once a ruthless, merciless warrior and an unparalleled architectural genius. Among his most notable military feats were repelling Egyptian campaigns and destroying the sacred city of Babylon, an act widely condemned. Yet in Nineveh he wrote his true legacy, transforming it from a mere city into a wonder of the world. He built the "Palace Without Rival" in history: eighty-two rooms whose walls were covered with stone reliefs depicting thousands of war, hunting, and ritual scenes with astonishing precision. He dug a fifty-kilometre canal to irrigate the gardens of Nineveh.',
    imageUrl:'assets/images/characters/sennacherib.jpg',
    birthYear:'~745 ق.م', deathYear:'681 ق.م',
    birthYearEn:'~745 BCE', deathYearEn:'681 BCE',
    achievements:['تحويل نينوى إلى عاصمة العالم القديم','بناء القصر الذي لا مثيل له بـ82 غرفة','حفر قناة مائية 50 كم لري الحدائق','صدّ الحملات المصرية المتكررة','صرح النقوش الحجرية الأضخم في التاريخ'],
    achievementsEn:['Transformed Nineveh into the capital of the ancient world','Built the 82-room "Palace Without Rival"','Dug a 50km canal to irrigate the gardens','Repelled repeated Egyptian campaigns','Created history\'s largest collection of stone relief carvings']),

  HistoricalCharacter(id:'c007', name:'أورنمو', nameEn:'Ur-Nammu',
    era:'~2112-2095 ق.م', civilization:'سومرية', role:'مؤسس أسرة أور الثالثة وأول مشرّع',
    eraEn:'~2112–2095 BCE', civilizationEn:'Sumerian', roleEn:'Founder of the Third Dynasty of Ur, First Lawgiver',
    description:'أورنمو مؤسس الأسرة الملكية لأور الثالثة وصانع نهضة سومر الذهبية في الألفية الثالثة قبل الميلاد. بدأ حياته المهنية والداً للملك أوتوهيغال ثم استقل بالسلطة وأعلن نفسه ملكاً على أور. أطلق عهده موجة إصلاحات شاملة طالت المجتمع والاقتصاد والعدالة؛ فوحّد نظام الأوزان والمكاييل ومنع الأقوياء من ابتلاع أراضي الضعفاء وحافظ على حقوق الأرامل والأيتام. وضع مجموعة قوانين تُعدّ الأقدم في التاريخ المكتوب متقدّمةً على قانون حمورابي بثلاثة قرون. شيّد زقورة أور الباقية حتى يومنا درّة عصره وشهادته الأبدية.',
    descriptionEn:'Ur-Nammu, founder of the royal Third Dynasty of Ur, ushered in Sumer\'s golden renaissance in the third millennium BCE. He began his career as a general under King Utu-hegal before seizing independent power and declaring himself king of Ur. His reign launched sweeping reforms touching society, economy, and justice: he standardized weights and measures, prevented the powerful from seizing the lands of the weak, and protected the rights of widows and orphans. He issued a law code regarded as the oldest in written history, predating Hammurabi\'s code by three centuries. He built the Ziggurat of Ur, which still stands today as the eternal testament to his era.',
    imageUrl:'assets/images/characters/ur_nammu.jpg',
    birthYear:'~2130 ق.م', deathYear:'2095 ق.م',
    birthYearEn:'~2130 BCE', deathYearEn:'2095 BCE',
    achievements:['تأسيس النهضة السومرية الذهبية لأسرة أور الثالثة','وضع أقدم مجموعة قوانين في التاريخ','بناء زقورة أور الخالدة','توحيد أوزان ومكاييل بلاد الرافدين','حماية حقوق الأرامل والأيتام والفقراء'],
    achievementsEn:['Launched the golden Sumerian renaissance of the Third Dynasty of Ur','Issued the oldest known law code in history','Built the eternal Ziggurat of Ur','Standardized weights and measures across Mesopotamia','Protected the rights of widows, orphans, and the poor']),

  HistoricalCharacter(id:'c016', name:'الإمام علي بن أبي طالب', nameEn:'Imam Ali',
    era:'600-661 م', civilization:'إسلامية', role:'الخليفة الرابع وأمير المؤمنين',
    eraEn:'600–661 CE', civilizationEn:'Islamic', roleEn:'Fourth Caliph and Commander of the Faithful',
    description:'الإمام علي بن أبي طالب ابن عم النبي محمد صلى الله عليه وسلم وزوج ابنته السيدة فاطمة الزهراء، رضي الله عنهما، رابع الخلفاء الراشدين وأول من أسلم من الذكور البالغين وفق بعض الروايات. اشتُهر بشجاعته الفائقة في المعارك وبعدل قضائه ودقة حكمه. اتخذ مدينة الكوفة في العراق عاصمةً لخلافته ومركزاً لدولته. خلّف وراءه كنزاً من الخطب والرسائل والحكم جُمعت في كتاب "نهج البلاغة" الذي ما زال يُدرَّس في جامعات العالم حتى اليوم كنموذج أدبي رفيع. اغتيل عام 661م في مسجد الكوفة ودُفن في النجف التي حملت اسمه وصارت من أقدس مدن الإسلام.',
    descriptionEn:'Imam Ali ibn Abi Talib, cousin of the Prophet Muhammad and husband of his daughter Fatima al-Zahra, was the fourth of the Rightly Guided Caliphs and, according to some accounts, the first adult male to embrace Islam. He was renowned for his extraordinary courage in battle and the fairness and precision of his judgments. He made Kufa in Iraq the capital of his caliphate and the centre of his state. He left behind a treasury of sermons, letters, and sayings collected in "Nahj al-Balagha," still studied in universities worldwide today as a literary masterpiece. He was assassinated in 661 CE in the mosque of Kufa and was buried in Najaf, which took his name and became one of the holiest cities in Islam.',
    imageUrl:'assets/images/characters/imam_ali.jpg',
    birthYear:'600 م', deathYear:'661 م',
    birthYearEn:'600 CE', deathYearEn:'661 CE',
    achievements:['رابع الخلفاء الراشدين','اتخاذ الكوفة عاصمةً للخلافة الإسلامية','نهج البلاغة تحفة الأدب العربي الإسلامي','القضاء العادل والحكم بين الناس','باب مدينة العلم النبوي وفق الأحاديث'],
    achievementsEn:['Fourth of the Rightly Guided Caliphs','Made Kufa the capital of the Islamic caliphate','"Nahj al-Balagha," a masterpiece of Arabic-Islamic literature','Renowned for fair judgment among the people','Described in hadith as the "gate" to the Prophet\'s knowledge']),

  HistoricalCharacter(id:'c017', name:'أبو جعفر المنصور', nameEn:'Al-Mansur',
    era:'754-775 م', civilization:'عباسية', role:'مؤسس بغداد عاصمة العالم',
    eraEn:'754–775 CE', civilizationEn:'Abbasid', roleEn:'Founder of Baghdad, Capital of the World',
    description:'أبو جعفر عبدالله المنصور ثاني الخلفاء العباسيين وحقيقي مؤسس الدولة العباسية، صاحب الحسن السياسي الذي لا يُضاهى. في عام 762م قرّر بناء عاصمة جديدة ليختار بنفسه موقعها على ضفة دجلة الغربية بين بلدتَي نهري صرصر وصاري. أشرف بنفسه على تصميم المدينة الدائرية الشهيرة ذات القطر الكيلومترَين والأربعة أسوار المتحدة المركز والقصر المركزي المذهب. شارك في بنائها مئة ألف عامل ومهندس من كل أنحاء الإمبراطورية. في عهده تحوّلت بغداد إلى أكبر مدن العالم وأكثرها ازدهاراً.',
    descriptionEn:'Abu Ja\'far Abdallah al-Mansur, second Abbasid caliph and true founder of the Abbasid state, possessed unmatched political acumen. In 762 CE he decided to build a new capital, personally selecting its site on the western bank of the Tigris between the canals of Sarsar and Sari. He personally oversaw the design of the famous Round City, two kilometres in diameter, with four concentric walls and a gilded central palace. A hundred thousand workers and engineers from across the empire took part in its construction. Under his rule, Baghdad became the largest and most prosperous city in the world.',
    imageUrl:'assets/images/characters/al_mansur.jpg',
    birthYear:'714 م', deathYear:'775 م',
    birthYearEn:'714 CE', deathYearEn:'775 CE',
    achievements:['تأسيس مدينة بغداد عام 762م','تصميم المدينة الدائرية المبتكرة','ترسيخ دعائم الدولة العباسية','ازدهار التجارة والعلوم','إخماد الثورات وتوطيد الحكم'],
    achievementsEn:['Founded the city of Baghdad in 762 CE','Designed the innovative Round City','Established the foundations of the Abbasid state','Fostered the flourishing of trade and science','Suppressed revolts and consolidated his rule']),

  HistoricalCharacter(id:'c018', name:'هارون الرشيد', nameEn:'Harun al-Rashid',
    era:'786-809 م', civilization:'عباسية', role:'خليفة العصر الذهبي الإسلامي',
    eraEn:'786–809 CE', civilizationEn:'Abbasid', roleEn:'Caliph of the Islamic Golden Age',
    description:'هارون الرشيد خامس الخلفاء العباسيين وأكثرهم شهرةً في الذاكرة الإنسانية، وُلد في الري ونشأ في كنف أستاذه البرامكة العظام. في عهده بلغت الخلافة العباسية ذروة ازدهارها وسيطرت على أكبر الإمبراطوريات في الشرق. جعل بغداد عاصمة العالم الثقافية والعلمية والتجارية؛ تدفّق إليها العلماء والأطباء والشعراء من الهند والصين وفارس واليونان. في عهده ازدهرت حركة الترجمة من اليونانية والفارسية والهندية. تبادل الهدايا مع الإمبراطور شارلمان ملك الفرنجة. خلّدت قصص ألف ليلة وليلة صورته في الأذهان.',
    descriptionEn:'Harun al-Rashid, fifth Abbasid caliph and the most famous in human memory, was born in Rayy and raised under the tutelage of the great Barmakid family. Under his rule, the Abbasid caliphate reached the height of its prosperity, controlling one of the greatest empires in the East. He made Baghdad the world\'s cultural, scientific, and commercial capital, drawing scholars, physicians, and poets from India, China, Persia, and Greece. The translation movement from Greek, Persian, and Indian sources flourished under his reign. He exchanged gifts with Emperor Charlemagne of the Franks. The tales of One Thousand and One Nights immortalized his image in popular memory.',
    imageUrl:'assets/images/characters/harun_rashid.jpg',
    birthYear:'763 م', deathYear:'809 م',
    birthYearEn:'763 CE', deathYearEn:'809 CE',
    achievements:['العصر الذهبي للحضارة الإسلامية','تحويل بغداد إلى عاصمة العالم','بيت الحكمة مركز الترجمة والعلوم','التبادل الدبلوماسي مع شارلمان','ألف ليلة وليلة تحفة التراث العالمي'],
    achievementsEn:['Presided over the Golden Age of Islamic civilization','Transformed Baghdad into the capital of the world','The House of Wisdom — centre of translation and science','Diplomatic exchanges with Charlemagne','Inspired One Thousand and One Nights, a world heritage masterpiece']),

  HistoricalCharacter(id:'c022', name:'الخوارزمي', nameEn:'Al-Khwarizmi',
    era:'780-850 م', civilization:'عباسية', role:'أبو الجبر وأبو الخوارزميات',
    eraEn:'780–850 CE', civilizationEn:'Abbasid', roleEn:'Father of Algebra and Algorithms',
    description:'محمد بن موسى الخوارزمي عالم الرياضيات الفذّ الذي تركت أعماله بصمة لا تُمحى في تاريخ العلوم الإنسانية حتى صار العالم الرقمي الحديث مدينا له بشكل مباشر. عمل في بيت الحكمة ببغداد في عهد الخليفة المأمون وألّف فيه أعظم أعماله. كتابه "الكتاب المختصر في حساب الجبر والمقابلة" هو المرجع الذي نشأ منه علم الجبر ووصلنا منه لفظ Algebra الإنجليزي المشتق من الجبر العربي. ومن اسمه "الخوارزمي" نُحتت كلمة Algorithm (خوارزمية) التي تُعدّ اليوم أساس علم الحاسوب والذكاء الاصطناعي. أدخل الأرقام الهندية (العربية) إلى الحضارة الإسلامية ومنها انتشرت إلى أوروبا.',
    descriptionEn:'Muhammad ibn Musa al-Khwarizmi was a brilliant mathematician whose work left an indelible mark on the history of human science, to the point that the modern digital world owes him a direct debt. He worked at the House of Wisdom in Baghdad under Caliph al-Ma\'mun, where he authored his greatest works. His book "The Compendious Book on Calculation by Completion and Balancing" gave rise to the science of algebra, and the English word "algebra" derives directly from its Arabic title. From his own name, "al-Khwarizmi," comes the word "algorithm," now the foundation of computer science and artificial intelligence. He introduced Hindu-Arabic numerals into Islamic civilization, from where they spread to Europe.',
    imageUrl:'assets/images/characters/al_khwarizmi.jpg',
    birthYear:'780 م', deathYear:'850 م',
    birthYearEn:'780 CE', deathYearEn:'850 CE',
    achievements:['اختراع علم الجبر ونشره للعالم','وضع مفهوم الخوارزمية أساس علم الحاسوب','تعريف الأرقام الهندية (العربية) للحضارة','علم الفلك والتقويم الخوارزمي','الجغرافيا وتصحيح خرائط بطليموس'],
    achievementsEn:['Invented and disseminated the science of algebra to the world','Originated the concept of the algorithm, foundation of computer science','Introduced Hindu-Arabic numerals to civilization','Contributed to astronomy and calendar science','Worked on geography, correcting Ptolemy\'s maps']),

  HistoricalCharacter(id:'c024', name:'المتنبي', nameEn:'Al-Mutanabbi',
    era:'915-965 م', civilization:'عباسية', role:'أمير الشعراء وفارس الكلمة',
    eraEn:'915–965 CE', civilizationEn:'Abbasid', roleEn:'Prince of Poets, Knight of the Word',
    description:'أبو الطيب أحمد بن الحسين المتنبي، المولود في الكوفة عام 915م، هو أعظم شاعر في تاريخ الأدب العربي بلا منازع عند كثيرين. نشأ نشأة متمرّدة وادّعى في شبابه النبوّة في بادية الشام فاعتُقل وعوقب ثم تاب. ظلّت طموحاته لا حدود لها وشعره مرآة لكبريائه الإنساني وعقله الجبّار. خدم في بلاط سيف الدولة الحمداني في حلب حيث أبدع قصائده الخالدة. جوّل في مصر والعراق وفارس تنهل منه الأمراء ويهبونه الذهب. قُتل عام 965م في غارة بالقرب من النعمانية جنوب بغداد. أبياته تُمثّل عقلاء العرب حتى اليوم.',
    descriptionEn:'Abu al-Tayyib Ahmad ibn al-Husayn al-Mutanabbi, born in Kufa in 915 CE, is regarded by many as the greatest poet in the history of Arabic literature, without rival. He had a rebellious upbringing and, in his youth, claimed prophethood in the Syrian desert, for which he was arrested, punished, and later recanted. His ambitions remained boundless, and his poetry mirrored his immense pride and formidable intellect. He served at the court of Sayf al-Dawla al-Hamdani in Aleppo, where he composed his most enduring verses. He travelled through Egypt, Iraq, and Persia, where princes sought his poetry and rewarded him in gold. He was killed in 965 CE in an ambush near al-Numaniyah, south of Baghdad. His verses still represent the wisdom of the Arabs to this day.',
    imageUrl:'assets/images/characters/al_mutanabbi.jpg',
    birthYear:'915 م', deathYear:'965 م',
    birthYearEn:'915 CE', deathYearEn:'965 CE',
    achievements:['لقب أمير الشعراء بإجماع الأجيال','ديوان شعر يُدرَّس في جامعات العالم','ابتكار أساليب شعرية لم تُسبق','شاعر سيف الدولة الحمداني الخالد','أمثال وحكم حيّة في الذاكرة العربية'],
    achievementsEn:['Hailed across generations as "Prince of Poets"','His Diwan is studied in universities worldwide','Pioneered unprecedented poetic styles','Court poet of Sayf al-Dawla al-Hamdani','His maxims and proverbs remain alive in Arab memory']),

