  HistoricalCharacter(id:'c036', name:'الرازي (أبو بكر الرازي)', nameEn:'Al-Razi',
    era:'854-925 م', civilization:'عباسية', role:'أبو الطب الإكلينيكي',
    eraEn:'854–925 CE', civilizationEn:'Abbasid', roleEn:'Father of Clinical Medicine',
    description:'محمد بن زكريا الرازي، الطبيب والفيلسوف والكيميائي الفذّ الذي يُعدّ أحد أعظم علماء الطب في التاريخ الإنساني. ترأّس بيمارستان بغداد الكبير وكتب الموسوعة الطبية الضخمة "الحاوي" التي ظلّت مرجعاً أساسياً في مدارس الطب الأوروبية قروناً. كان أول من فرّق طبياً بين الجدري والحصبة. أجرى تجارب علمية دقيقة في الكيمياء ووضع أسس التحليل العقلاني في الطب. يُعدّ المؤسس الحقيقي للطب الإكلينيكي الذي يعتمد على الملاحظة والتجريب.',
    descriptionEn:'Muhammad ibn Zakariya al-Razi was a brilliant physician, philosopher, and chemist regarded as one of the greatest medical scholars in human history. He headed the great hospital of Baghdad and wrote the massive medical encyclopedia "Al-Hawi," which remained a core reference in European medical schools for centuries. He was the first to medically distinguish between smallpox and measles. He conducted precise scientific experiments in chemistry and laid the foundations of rational analysis in medicine. He is considered the true founder of clinical medicine, based on observation and experimentation.',
    imageUrl:'assets/images/characters/al_razi.jpg',
    birthYear:'854 م', deathYear:'925 م',
    birthYearEn:'854 CE', deathYearEn:'925 CE',
    achievements:['أبو الطب الإكلينيكي التجريبي','موسوعة الحاوي مرجع أوروبا الطبي','أول من فرّق بين الجدري والحصبة','رئاسة بيمارستان بغداد الكبير','أسس التحليل العلمي في الكيمياء والطب'],
    achievementsEn:['Father of experimental clinical medicine','"Al-Hawi" encyclopedia, a core European medical reference','First to distinguish smallpox from measles','Headed the great hospital of Baghdad','Established scientific analysis in chemistry and medicine']),

  HistoricalCharacter(id:'c037', name:'ابن سينا', nameEn:'Ibn Sina (Avicenna)',
    era:'980-1037 م', civilization:'عباسية', role:'الشيخ الرئيس وأمير الأطباء',
    eraEn:'980–1037 CE', civilizationEn:'Abbasid', roleEn:'The "Leading Master," Prince of Physicians',
    description:'أبو علي الحسين بن عبدالله بن سينا، المعروف في الغرب بـ Avicenna، الموسوعي العبقري الذي يُعدّ من أعظم علماء البشرية قاطبة. ألّف أكثر من 450 كتاباً في الطب والفلسفة والرياضيات والفلك والموسيقى. كتابه "القانون في الطب" ظلّ المرجع الطبي الأول في جامعات أوروبا وآسيا حتى القرن السابع عشر. أثرى بغداد وسامراء بعلمه الغزير ووضع نظرية الأخلاط الطبية التي رسّخت أساس علم التشخيص.',
    descriptionEn:'Abu Ali al-Husayn ibn Abdallah Ibn Sina, known in the West as Avicenna, was a brilliant polymath ranked among the greatest scholars humanity has ever produced. He authored more than 450 books on medicine, philosophy, mathematics, astronomy, and music. His book "The Canon of Medicine" remained the leading medical reference in European and Asian universities until the 17th century. He enriched Baghdad and Samarra with his vast learning and developed humor theory in medicine, laying the foundations of diagnostic science.',
    imageUrl:'assets/images/characters/ibn_sina.jpg',
    birthYear:'980 م', deathYear:'1037 م',
    birthYearEn:'980 CE', deathYearEn:'1037 CE',
    achievements:['القانون في الطب أهم كتاب طبي في التاريخ','450 مؤلفاً في العلوم والفلسفة','الشيخ الرئيس للفلسفة الإسلامية','أساس علم الأدوية والتشريح','أبو الطب الحديث وفق كثير من المؤرخين'],
    achievementsEn:['"The Canon of Medicine," history\'s most influential medical text','Authored 450 works across science and philosophy','Recognized as the leading master of Islamic philosophy','Laid foundations for pharmacology and anatomy','Regarded by many historians as the father of modern medicine']),

  HistoricalCharacter(id:'c038', name:'نبوخذنصر الثاني', nameEn:'Nebuchadnezzar II',
    era:'605-562 ق.م', civilization:'بابلية', role:'ملك بابل وباني عجائبها',
    eraEn:'605–562 BCE', civilizationEn:'Babylonian', roleEn:'King of Babylon, Builder of its Wonders',
    description:'نبوخذنصر الثاني أعظم ملوك الإمبراطورية البابلية الجديدة وأشهرهم على الإطلاق. في عهده بلغت بابل ذروة مجدها وأبّهتها وصارت قبلة الدنيا. شيّد حدائق بابل المعلقة لزوجته الميدية أميتيس اشتياقاً منها لجبال موطنها الخضراء، فكانت من عجائب الدنيا السبع. بنى بوابة عشتار الأسطورية المزيّنة بالقرميد الأزرق اللازوردي وجدّد شارع الموكب المقدس. حاصر أورشليم مرتين وأسر بني إسرائيل إلى بابل في ما عُرف بـ"السبي البابلي" المذكور في الكتاب المقدس.',
    descriptionEn:'Nebuchadnezzar II was the greatest and most famous king of the Neo-Babylonian Empire. Under his rule, Babylon reached the height of its glory and splendour, becoming the envy of the world. He built the Hanging Gardens of Babylon for his Median wife Amytis, who longed for the green mountains of her homeland, making them one of the Seven Wonders of the Ancient World. He built the legendary Ishtar Gate, adorned with blue lapis tiles, and renovated the sacred Processional Way. He besieged Jerusalem twice and exiled the Israelites to Babylon in what became known as the "Babylonian Captivity," recorded in the Bible.',
    imageUrl:'assets/images/characters/nebuchadnezzar.jpg',
    birthYear:'~634 ق.م', deathYear:'562 ق.م',
    birthYearEn:'~634 BCE', deathYearEn:'562 BCE',
    achievements:['بناء حدائق بابل المعلقة إحدى عجائب الدنيا','تشييد بوابة عشتار الأسطورية','تحويل بابل إلى أعظم مدن العالم القديم','الإمبراطورية البابلية الجديدة في ذروتها','السبي البابلي المذكور في الكتب المقدسة'],
    achievementsEn:['Built the Hanging Gardens of Babylon, a Wonder of the World','Constructed the legendary Ishtar Gate','Made Babylon the greatest city of the ancient world','Led the Neo-Babylonian Empire at its peak','The Babylonian Captivity, recorded in sacred scripture']),

];
